  ExerciseInfo(name: 'Decline Dumbbell Triceps Extension', nameEn: 'Decline Dumbbell Triceps Extension', category: 'braccia', muscleImages: ['tricipiti.png'], primaryMuscle: 'Tricipiti', secondaryMuscles: 'Deltoide anteriore, Grande pettorale', execution: 'Estendi completamente le braccia nella fase concentrica. Torna lentamente alla posizione di partenza controllando il movimento.', tips: 'Mantieni i gomiti fermi. Concentrati sulla contrazione completa.', gifFilename: 'decline-dumbbell-triceps-extension'),
  ExerciseInfo(name: 'Decline Hammer Press', nameEn: 'Decline Hammer Press', category: 'altro', muscleImages: [], primaryMuscle: 'Muscolatura principale coinvolta', secondaryMuscles: 'Muscolatura di supporto', execution: 'Esegui il movimento lentamente e con controllo. Mantieni una postura corretta.', tips: 'Inizia con peso moderato per padroneggiare la tecnica.', gifFilename: 'decline-hammer-press'),
  ExerciseInfo(name: 'Decline Push Up', nameEn: 'Decline Push Up', category: 'petto', muscleImages: ['petto.png', 'push.png'], primaryMuscle: 'Grande pettorale (fascio clavicolare)', secondaryMuscles: 'Tricipiti, Core', execution: 'Con i piedi su una superficie rialzata, abbassa il petto verso il suolo. Spingi verso l\'alto tornando alla posizione di partenza.', tips: 'Più alta è la superficie, più lavora la parte alta del petto.', gifFilename: 'decline-push-up'),
  ExerciseInfo(name: 'Decline Sit Up', nameEn: 'Decline Sit Up', category: 'core', muscleImages: [], primaryMuscle: 'Rettosaddominale', secondaryMuscles: 'Obliqui', execution: 'Sdraiati con le ginocchia piegate. Porta le spalle verso le ginocchia contraendo l\'addome. Abbassa lentamente.', tips: 'Non tirare il collo. Concentrati sulla contrazione dell\'addome.', gifFilename: 'decline-sit-up'),
  ExerciseInfo(name: 'Depth Jump To Hurdle Hop', nameEn: 'Depth Jump To Hurdle Hop', category: 'altro', muscleImages: ['quadricipiti.png', 'glutei.png'], primaryMuscle: 'Quadricipiti, Glutei, Polpacci', secondaryMuscles: 'Ischiocrurali, Core', execution: 'Esegui il movimento esplosivo verso l\'alto o in avanti. Atterrai morbidamente flettendo le ginocchia. Controlla l\'atterraggio.', tips: 'Atterrai sempre morbidamente. Non bloccare le ginocchia.', gifFilename: 'depth-jump-to-hurdle-hop'),
  ExerciseInfo(name: 'Dhanurasana Rocking Bow Pose', nameEn: 'Dhanurasana Rocking Bow Pose', category: 'altro', muscleImages: [], primaryMuscle: 'Mobilità articolare generale', secondaryMuscles: 'Muscolatura di supporto', execution: 'Porta il corpo in posizione di allungamento. Mantieni 20-30 secondi.', tips: 'Respira profondamente. Non forzare mai oltre il limite naturale.', gifFilename: 'dhanurasana-rocking-bow-pose'),
  ExerciseInfo(name: 'Diamond Push Up', nameEn: 'Diamond Push Up', category: 'petto', muscleImages: ['tricipiti.png', 'push.png'], primaryMuscle: 'Tricipiti', secondaryMuscles: 'Grande pettorale, Deltoide anteriore', execution: 'Posiziona le mani a forma di diamante sotto il petto. Abbassa il corpo mantenendo i gomiti vicini al busto. Spingi verso l\'alto contraendo i tricipiti.', tips: 'La presa stretta isola i tricipiti. Mantieni il corpo in linea retta.', gifFilename: 'diamond-push-up'),
  ExerciseInfo(name: 'Dip Shrugs Serratus Shrugs', nameEn: 'Dip Shrugs Serratus Shrugs', category: 'spalle', muscleImages: ['petto.png', 'tricipiti.png'], primaryMuscle: 'Grande pettorale, Tricipiti', secondaryMuscles: 'Deltoide anteriore', execution: 'Afferrare le parallele con le braccia tese. Abbassa il corpo inclinando leggermente il busto in avanti flettendo i gomiti. Spingi verso l\'alto tornando alla posizione di partenza.', tips: 'L\'inclinazione in avanti aumenta il coinvolgimento del petto. La posizione verticale isola i tricipiti.', gifFilename: 'dip-shrugs-serratus-shrugs'),
  ExerciseInfo(name: 'Dips Between Chairs', nameEn: 'Dips Between Chairs', category: 'braccia', muscleImages: ['tricipiti.png'], primaryMuscle: 'Tricipiti', secondaryMuscles: 'Grande pettorale, Deltoide anteriore', execution: 'Con le mani sul bordo di una panca, avanza con i glutei fuori. Abbassa il corpo flettendo i gomiti a 90°. Spingi verso l\'alto.', tips: 'Mantieni il busto verticale per isolare i tricipiti. Più ti abbassi, maggiore è il coinvolgimento del petto.', gifFilename: 'dips-between-chairs'),
  ExerciseInfo(name: 'Donkey Calf Raise', nameEn: 'Donkey Calf Raise', category: 'gambe', muscleImages: ['gambe.png'], primaryMuscle: 'Gastrocnemio, Soleo', secondaryMuscles: 'Tibiale anteriore', execution: 'In piedi con i talloni oltre il bordo di un rialzo. Alza sulle punte dei piedi contraendo i polpacci. Abbassa lentamente lasciando scendere i talloni sotto il livello del rialzo.', tips: 'Esegui il movimento lentamente in entrambe le fasi. La pausa in basso aumenta l\'allungamento del polpaccio.', gifFilename: 'donkey-calf-raise'),
  ExerciseInfo(name: 'Donkey Kick On Leg Extension Machine', nameEn: 'Donkey Kick On Leg Extension Machine', category: 'glutei', muscleImages: ['quadricipiti.png'], primaryMuscle: 'Quadricipiti', secondaryMuscles: 'Nessuno significativo', execution: 'Siediti alla macchina con i cuscinetti sulle caviglie. Estendi le gambe verso l\'alto contraendo i quadricipiti. Abbassa lentamente.', tips: 'Mantieni la contrazione in cima per un secondo. Evita lo slancio.', gifFilename: 'donkey-kick-on-leg-extension-machine'),
  ExerciseInfo(name: 'Donkey Kick On Smith Machine', nameEn: 'Donkey Kick On Smith Machine', category: 'glutei', muscleImages: ['glutei.png'], primaryMuscle: 'Gluteo grande', secondaryMuscles: 'Ischiocrurali, Lombari', execution: 'In appoggio su mani e ginocchia o in piedi al cavo. Estendi la gamba verso l\'indietro contraendo il gluteo. Torna lentamente.', tips: 'Mantieni il core contratto per proteggere la schiena. Evita di iperestendere la colonna lombare.', gifFilename: 'donkey-kick-on-smith-machine'),
