  ExerciseInfo(name: 'Dumbbell Glute Bridge', nameEn: 'Dumbbell Glute Bridge', category: 'glutei', muscleImages: ['glutei.png', 'femorali.png'], primaryMuscle: 'Gluteo grande', secondaryMuscles: 'Ischiocrurali, Core', execution: 'Con la parte superiore della schiena su una panca e il peso sulle anche. Spingi le anche verso l\'alto contraendo i glutei. Torna lentamente.', tips: 'Mantieni la contrazione in cima per un secondo. Mantieni il mento verso il petto.', gifFilename: 'dumbbell-glute-bridge'),
  ExerciseInfo(name: 'Dumbbell Goblet Curtsey Lunge', nameEn: 'Dumbbell Goblet Curtsey Lunge', category: 'gambe', muscleImages: ['quadricipiti.png', 'glutei.png'], primaryMuscle: 'Quadricipiti, Glutei', secondaryMuscles: 'Ischiocrurali, Polpacci', execution: 'Fai un passo avanti abbassando il ginocchio posteriore verso il suolo. Il ginocchio anteriore rimane allineato con la caviglia. Spingi tornando.', tips: 'Mantieni il busto eretto e il core contratto. Evita che il ginocchio anteriore superi la punta del piede.', gifFilename: 'dumbbell-goblet-curtsey-lunge'),
  ExerciseInfo(name: 'Dumbbell Goblet Squat', nameEn: 'Dumbbell Goblet Squat', category: 'gambe', muscleImages: ['quadricipiti.png', 'glutei.png'], primaryMuscle: 'Quadricipiti, Glutei', secondaryMuscles: 'Ischiocrurali, Core', execution: 'In piedi con i piedi alla larghezza delle spalle, tieni un manubrio davanti al petto. Scendi mantenendo il petto alto. Torna su spingendo sui talloni.', tips: 'Il peso davanti aiuta la postura verticale. Mantieni le ginocchia allineate.', gifFilename: 'dumbbell-goblet-squat'),
  ExerciseInfo(name: 'Dumbbell Good Morning', nameEn: 'Dumbbell Good Morning', category: 'altro', muscleImages: ['femorali.png', 'dorso.png'], primaryMuscle: 'Ischiocrurali, Lombari', secondaryMuscles: 'Glutei, Gran dorsale', execution: 'In piedi con il bilanciere sulle spalle. Inclina il busto in avanti mantenendo la schiena dritta e le ginocchia leggermente piegate. Senti lo stretching degli ischiocrurali. Torna alla posizione eretta.', tips: 'Non arrotondare la schiena. Inizia con un peso leggero.', gifFilename: 'dumbbell-good-morning'),
  ExerciseInfo(name: 'Dumbbell High Curl', nameEn: 'Dumbbell High Curl', category: 'braccia', muscleImages: ['bicipiti.png'], primaryMuscle: 'Bicipiti', secondaryMuscles: 'Brachiale, Brachioradiale', execution: 'Fletti i gomiti portando il peso verso le spalle. Abbassa lentamente.', tips: 'Mantieni i gomiti fissi. Non usare lo slancio.', gifFilename: 'dumbbell-high-curl'),
  ExerciseInfo(name: 'Dumbbell Incline Shrug', nameEn: 'Dumbbell Incline Shrug', category: 'spalle', muscleImages: ['spalle.png'], primaryMuscle: 'Trapezio', secondaryMuscles: 'Elevatore della scapola, Romboidi', execution: 'In piedi con un peso per mano lungo i fianchi. Alza le spalle verso le orecchie contraendo il trapezio. Mantieni la contrazione un secondo poi abbassa lentamente.', tips: 'Evita di ruotare le spalle. Concentrati solo sul movimento verticale.', gifFilename: 'dumbbell-incline-shrug'),
