  ExerciseInfo(name: 'Dumbbell Jefferson Curl', nameEn: 'Dumbbell Jefferson Curl', category: 'braccia', muscleImages: ['bicipiti.png'], primaryMuscle: 'Bicipiti', secondaryMuscles: 'Brachiale, Brachioradiale', execution: 'Fletti i gomiti portando il peso verso le spalle. Abbassa lentamente.', tips: 'Mantieni i gomiti fissi. Non usare lo slancio.', gifFilename: 'dumbbell-jefferson-curl'),
  ExerciseInfo(name: 'Dumbbell Jump Squat', nameEn: 'Dumbbell Jump Squat', category: 'cardio', muscleImages: ['quadricipiti.png', 'glutei.png'], primaryMuscle: 'Quadricipiti, Glutei', secondaryMuscles: 'Ischiocrurali, Polpacci', execution: 'Scendi in squat poi salta verso l\'alto esplosivamente. Atterrai morbidamente flettendo le ginocchia.', tips: 'Atterrai sempre in modo morbido. Non bloccare le ginocchia.', gifFilename: 'dumbbell-jump-squat'),
  ExerciseInfo(name: 'Dumbbell Kickback', nameEn: 'Dumbbell Kickback', category: 'braccia', muscleImages: ['braccia.png'], primaryMuscle: 'Bicipiti, Tricipiti', secondaryMuscles: 'Muscoli avambraccio', execution: 'Esegui il movimento controllando fase eccentrica e concentrica. Mantieni i gomiti fissi.', tips: 'Non usare lo slancio. Concentrati sulla contrazione.', gifFilename: 'dumbbell-kickback'),
  ExerciseInfo(name: 'Dumbbell Lateral Raise', nameEn: 'Dumbbell Lateral Raise', category: 'spalle', muscleImages: ['spalle.png'], primaryMuscle: 'Deltoide laterale', secondaryMuscles: 'Trapezio superiore, Sovraspinato', execution: 'In piedi con un manubrio per mano lungo i fianchi. Alza le braccia lateralmente fino all\'altezza delle spalle mantenendo i gomiti leggermente piegati. Abbassa lentamente.', tips: 'Non portare le braccia oltre l\'altezza delle spalle. Ruota leggermente i polsi verso il basso (come versando acqua) per isolare il deltoide laterale.', gifFilename: 'dumbbell-lateral-raise'),
  ExerciseInfo(name: 'Dumbbell Lateral Step Up', nameEn: 'Dumbbell Lateral Step Up', category: 'gambe', muscleImages: ['quadricipiti.png', 'glutei.png'], primaryMuscle: 'Quadricipiti, Glutei', secondaryMuscles: 'Ischiocrurali, Polpacci', execution: 'In piedi di fronte a una panca. Appoggia un piede sul rialzo e spingi verso l\'alto. Abbassa lentamente controllando il movimento.', tips: 'Spingi principalmente con il piede sul rialzo. Mantieni il busto eretto.', gifFilename: 'dumbbell-lateral-step-up'),
  ExerciseInfo(name: 'Dumbbell Lateral To Front Raise', nameEn: 'Dumbbell Lateral To Front Raise', category: 'spalle', muscleImages: ['spalle.png'], primaryMuscle: 'Deltoide anteriore', secondaryMuscles: 'Grande pettorale (fascio clavicolare), Trapezio', execution: 'In piedi con l\'attrezzo davanti alle cosce. Alza le braccia davanti a te fino all\'altezza delle spalle mantenendo i gomiti leggermente piegati. Abbassa lentamente.', tips: 'Mantieni il busto stabile evitando di dondolare. Controlla la discesa.', gifFilename: 'dumbbell-lateral-to-front-raise'),
