  ExerciseInfo(name: 'Dumbbell One Arm Shoulder Press', nameEn: 'Dumbbell One Arm Shoulder Press', category: 'spalle', muscleImages: ['spalle.png', 'tricipiti.png'], primaryMuscle: 'Deltoide (fascio anteriore e laterale)', secondaryMuscles: 'Trapezio superiore, Tricipiti', execution: 'In piedi o seduto con l\'attrezzo all\'altezza delle spalle. Spingi verso l\'alto estendendo completamente le braccia. Abbassa lentamente tornando alla posizione di partenza con il peso all\'altezza delle spalle.', tips: 'Mantieni il core contratto e la schiena dritta. Evita di iperestendere la colonna lombare.', gifFilename: 'dumbbell-one-arm-shoulder-press'),
  ExerciseInfo(name: 'Dumbbell Pistol Squat', nameEn: 'Dumbbell Pistol Squat', category: 'gambe', muscleImages: ['quadricipiti.png', 'glutei.png'], primaryMuscle: 'Quadricipiti, Glutei', secondaryMuscles: 'Ischiocrurali, Polpacci', execution: 'In posizione di affondo monolaterale. Abbassa il corpo flettendo il ginocchio anteriore. Spingi verso l\'alto tornando alla partenza.', tips: 'Mantieni il ginocchio anteriore allineato con la punta del piede. Corregge gli squilibri tra le gambe.', gifFilename: 'dumbbell-pistol-squat'),
