  ExerciseInfo(name: 'Dumbbell Triceps Extension', nameEn: 'Dumbbell Triceps Extension', category: 'braccia', muscleImages: ['tricipiti.png'], primaryMuscle: 'Tricipiti', secondaryMuscles: 'Deltoide anteriore, Grande pettorale', execution: 'Estendi completamente le braccia nella fase concentrica. Torna lentamente alla posizione di partenza controllando il movimento.', tips: 'Mantieni i gomiti fermi. Concentrati sulla contrazione completa.', gifFilename: 'dumbbell-triceps-extension'),
  ExerciseInfo(name: 'Dumbbell Upright Row', nameEn: 'Dumbbell Upright Row', category: 'dorso', muscleImages: ['spalle.png', 'dorso.png'], primaryMuscle: 'Deltoide, Trapezio', secondaryMuscles: 'Bicipiti, Romboidi', execution: 'In piedi con l\'attrezzo davanti alle cosce con presa prona. Tira verso il mento mantenendo i gomiti più alti dei polsi. Abbassa lentamente.', tips: 'Evita di alzare i gomiti oltre l\'altezza delle spalle. Una presa più larga riduce il rischio di impingement.', gifFilename: 'dumbbell-upright-row'),
