  ExerciseInfo(name: 'Half Frog Pose', nameEn: 'Half Frog Pose', category: 'altro', muscleImages: [], primaryMuscle: 'Mobilità articolare generale', secondaryMuscles: 'Muscolatura di supporto', execution: 'Porta il corpo in posizione di allungamento. Mantieni 20-30 secondi.', tips: 'Respira profondamente. Non forzare mai oltre il limite naturale.', gifFilename: 'half-frog-pose'),
  ExerciseInfo(name: 'Half Kneeling Cable External Rotation', nameEn: 'Half Kneeling Cable External Rotation', category: 'altro', muscleImages: [], primaryMuscle: 'Muscolatura principale coinvolta', secondaryMuscles: 'Muscolatura di supporto', execution: 'Esegui il movimento lentamente e con controllo. Mantieni una postura corretta.', tips: 'Inizia con peso moderato per padroneggiare la tecnica.', gifFilename: 'half-kneeling-cable-external-rotation'),
  ExerciseInfo(name: 'Half Kneeling High Cable Row Rope', nameEn: 'Half Kneeling High Cable Row Rope', category: 'petto', muscleImages: ['dorso.png', 'bicipiti.png'], primaryMuscle: 'Gran dorsale, Romboidi', secondaryMuscles: 'Bicipiti, Trapezio, Deltoide posteriore', execution: 'Siediti al cavo basso con i piedi sui supporti. Tira la maniglia verso il punto vita mantenendo la schiena dritta. Contrai i muscoli della schiena e torna lentamente.', tips: 'Non arrotondare la schiena. Controlla la fase di allungamento.', gifFilename: 'half-kneeling-high-cable-row-rope'),
  ExerciseInfo(name: 'Half Kneeling Lat Pulldown', nameEn: 'Half Kneeling Lat Pulldown', category: 'dorso', muscleImages: ['dorso.png', 'pull.png'], primaryMuscle: 'Gran dorsale', secondaryMuscles: 'Romboidi, Bicipiti, Deltoide posteriore', execution: 'Siediti alla lat machine e afferra la sbarra con presa prona più larga delle spalle. Tira la sbarra verso il petto inclinando leggermente il busto. Controlla il ritorno alla posizione di partenza.', tips: 'Inizia dalla retrazione delle scapole. Non portare il busto troppo indietro.', gifFilename: 'half-kneeling-lat-pulldown'),
