  ExerciseInfo(name: 'Kettlebell Clean And Press', nameEn: 'Kettlebell Clean And Press', category: 'altro', muscleImages: [], primaryMuscle: 'Muscolatura principale coinvolta', secondaryMuscles: 'Muscolatura di supporto', execution: 'Esegui il movimento lentamente e con controllo. Mantieni una postura corretta.', tips: 'Inizia con peso moderato per padroneggiare la tecnica.', gifFilename: 'kettlebell-clean-and-press'),
  ExerciseInfo(name: 'Kettlebell Deadlift', nameEn: 'Kettlebell Deadlift', category: 'dorso', muscleImages: ['femorali.png', 'glutei.png', 'dorso.png'], primaryMuscle: 'Ischiocrurali, Glutei, Lombari', secondaryMuscles: 'Quadricipiti, Gran dorsale, Trapezio', execution: 'In piedi con i piedi alla larghezza delle anche. Abbassati con la schiena dritta e il petto alto. Spingi i piedi a terra e stendi anche e ginocchia contemporaneamente mantenendo la barra aderente alle gambe.', tips: 'Non arrotondare la schiena in nessuna fase. Blocca il core prima di tirare.', gifFilename: 'kettlebell-deadlift'),
  ExerciseInfo(name: 'Kettlebell Deep Push Up', nameEn: 'Kettlebell Deep Push Up', category: 'petto', muscleImages: ['petto.png', 'push.png'], primaryMuscle: 'Grande pettorale, Tricipiti', secondaryMuscles: 'Deltoide anteriore, Core', execution: 'In posizione prona con le mani alla larghezza delle spalle. Abbassa il petto verso il suolo flettendo i gomiti. Spingi verso l\'alto tornando alla posizione di partenza mantenendo il corpo in linea retta.', tips: 'Non lasciare che i fianchi cedano verso il basso. Retrai le scapole.', gifFilename: 'kettlebell-deep-push-up'),
  ExerciseInfo(name: 'Kettlebell Figure 8', nameEn: 'Kettlebell Figure 8', category: 'altro', muscleImages: [], primaryMuscle: 'Muscolatura principale coinvolta', secondaryMuscles: 'Muscolatura di supporto', execution: 'Esegui il movimento lentamente e con controllo. Mantieni una postura corretta.', tips: 'Inizia con peso moderato per padroneggiare la tecnica.', gifFilename: 'kettlebell-figure-8'),
  ExerciseInfo(name: 'Kettlebell Front Squat', nameEn: 'Kettlebell Front Squat', category: 'gambe', muscleImages: ['quadricipiti.png', 'glutei.png'], primaryMuscle: 'Quadricipiti', secondaryMuscles: 'Glutei, Ischiocrurali, Core', execution: 'Bilanciere sulla parte anteriore delle spalle con gomiti alti. Scendi mantenendo il busto il più verticale possibile. Torna su spingendo.', tips: 'I gomiti alti impediscono al bilanciere di scivolare. Richiede molta mobilità di polso e caviglia.', gifFilename: 'kettlebell-front-squat'),
  ExerciseInfo(name: 'Kettlebell Goblet Squat', nameEn: 'Kettlebell Goblet Squat', category: 'gambe', muscleImages: ['quadricipiti.png', 'glutei.png'], primaryMuscle: 'Quadricipiti, Glutei', secondaryMuscles: 'Ischiocrurali, Core', execution: 'In piedi con i piedi alla larghezza delle spalle, tieni un manubrio davanti al petto. Scendi mantenendo il petto alto. Torna su spingendo sui talloni.', tips: 'Il peso davanti aiuta la postura verticale. Mantieni le ginocchia allineate.', gifFilename: 'kettlebell-goblet-squat'),
