  ExerciseInfo(name: 'One Arm Biceps Curl With Resistance Band', nameEn: 'One Arm Biceps Curl With Resistance Band', category: 'braccia', muscleImages: ['bicipiti.png'], primaryMuscle: 'Bicipiti', secondaryMuscles: 'Brachiale, Brachioradiale', execution: 'In piedi con l\'attrezzo con presa supinata. Fletti i gomiti portando l\'attrezzo verso le spalle mantenendo i gomiti fissi ai lati del busto. Abbassa lentamente tornando alla posizione di partenza.', tips: 'Mantieni i gomiti fissi durante tutto il movimento. Concentrati sulla contrazione completa in cima.', gifFilename: 'one-arm-biceps-curl-with-resistance-band'),
  ExerciseInfo(name: 'One Arm Biceps Curl', nameEn: 'One Arm Biceps Curl', category: 'braccia', muscleImages: ['bicipiti.png'], primaryMuscle: 'Bicipiti', secondaryMuscles: 'Brachiale, Brachioradiale', execution: 'In piedi con l\'attrezzo con presa supinata. Fletti i gomiti portando l\'attrezzo verso le spalle mantenendo i gomiti fissi ai lati del busto. Abbassa lentamente tornando alla posizione di partenza.', tips: 'Mantieni i gomiti fissi durante tutto il movimento. Concentrati sulla contrazione completa in cima.', gifFilename: 'one-arm-biceps-curl'),
