  ExerciseInfo(name: 'Plate Loaded Seated Row', nameEn: 'Plate Loaded Seated Row', category: 'dorso', muscleImages: ['dorso.png', 'bicipiti.png'], primaryMuscle: 'Gran dorsale, Romboidi', secondaryMuscles: 'Bicipiti, Trapezio, Deltoide posteriore', execution: 'Siediti al cavo basso con i piedi sui supporti. Tira la maniglia verso il punto vita mantenendo la schiena dritta. Contrai i muscoli della schiena e torna lentamente.', tips: 'Non arrotondare la schiena. Controlla la fase di allungamento.', gifFilename: 'plate-loaded-seated-row'),
  ExerciseInfo(name: 'Plate Loaded Shoulder Press', nameEn: 'Plate Loaded Shoulder Press', category: 'spalle', muscleImages: ['spalle.png', 'tricipiti.png'], primaryMuscle: 'Deltoide (fascio anteriore e laterale)', secondaryMuscles: 'Trapezio superiore, Tricipiti', execution: 'In piedi o seduto con l\'attrezzo all\'altezza delle spalle. Spingi verso l\'alto estendendo completamente le braccia. Abbassa lentamente tornando alla posizione di partenza con il peso all\'altezza delle spalle.', tips: 'Mantieni il core contratto e la schiena dritta. Evita di iperestendere la colonna lombare.', gifFilename: 'plate-loaded-shoulder-press'),
  ExerciseInfo(name: 'Plate Push', nameEn: 'Plate Push', category: 'altro', muscleImages: [], primaryMuscle: 'Muscolatura principale coinvolta', secondaryMuscles: 'Muscolatura di supporto', execution: 'Esegui il movimento lentamente e con controllo. Mantieni una postura corretta.', tips: 'Inizia con peso moderato per padroneggiare la tecnica.', gifFilename: 'plate-push'),
  ExerciseInfo(name: 'Plyo Jacks', nameEn: 'Plyo Jacks', category: 'altro', muscleImages: [], primaryMuscle: 'Muscolatura principale coinvolta', secondaryMuscles: 'Muscolatura di supporto', execution: 'Esegui il movimento lentamente e con controllo. Mantieni una postura corretta.', tips: 'Inizia con peso moderato per padroneggiare la tecnica.', gifFilename: 'plyo-jacks'),
  ExerciseInfo(name: 'Posterior Tibialis Stretch', nameEn: 'Posterior Tibialis Stretch', category: 'altro', muscleImages: ['femorali.png'], primaryMuscle: 'Ischiocrurali', secondaryMuscles: 'Lombari, Glutei', execution: 'Porta la gamba in posizione di allungamento con la schiena dritta. Mantieni per 20-30 secondi respirando profondamente.', tips: 'Tensione moderata, mai dolore. Espira allungandoti.', gifFilename: 'posterior-tibialis-stretch'),
  ExerciseInfo(name: 'Power Clean', nameEn: 'Power Clean', category: 'altro', muscleImages: [], primaryMuscle: 'Muscolatura principale coinvolta', secondaryMuscles: 'Muscolatura di supporto', execution: 'Esegui il movimento lentamente e con controllo. Mantieni una postura corretta.', tips: 'Inizia con peso moderato per padroneggiare la tecnica.', gifFilename: 'power-clean'),
  ExerciseInfo(name: 'Power Lunge', nameEn: 'Power Lunge', category: 'gambe', muscleImages: ['quadricipiti.png', 'glutei.png'], primaryMuscle: 'Quadricipiti, Glutei', secondaryMuscles: 'Ischiocrurali, Polpacci', execution: 'Fai un passo avanti abbassando il ginocchio posteriore verso il suolo. Il ginocchio anteriore rimane allineato con la caviglia. Spingi tornando.', tips: 'Mantieni il busto eretto e il core contratto. Evita che il ginocchio anteriore superi la punta del piede.', gifFilename: 'power-lunge'),
