  ExerciseInfo(name: 'Pull Up', nameEn: 'Pull Up', category: 'dorso', muscleImages: ['dorso.png', 'pull.png'], primaryMuscle: 'Gran dorsale', secondaryMuscles: 'Romboidi, Bicipiti, Deltoide posteriore', execution: 'Afferrare la sbarra con presa prona alla larghezza delle spalle. Partendo con le braccia tese, tira il corpo verso l\'alto finché il mento supera la sbarra. Abbassa lentamente tornando alla posizione di partenza.', tips: 'Inizia il movimento dalla retrazione delle scapole. Evita lo slancio.', gifFilename: 'pull-up'),
  ExerciseInfo(name: 'Punches', nameEn: 'Punches', category: 'cardio', muscleImages: [], primaryMuscle: 'Sistema cardiovascolare', secondaryMuscles: 'Muscolatura arti inferiori', execution: 'Mantieni un ritmo costante. Postura corretta durante tutto l\'esercizio.', tips: 'Inizia a ritmo moderato e aumenta gradualmente.', gifFilename: 'punches'),
