  ExerciseInfo(name: 'Push Press', nameEn: 'Push Press', category: 'petto', muscleImages: ['petto.png'], primaryMuscle: 'Grande pettorale', secondaryMuscles: 'Tricipiti, Deltoide anteriore', execution: 'Esegui il movimento controllando fase eccentrica e concentrica. Mantieni le scapole retratte.', tips: 'Retrai le scapole per stabilizzare la spalla.', gifFilename: 'push-press'),
