  ExerciseInfo(name: 'Seated Cable Chest Press', nameEn: 'Seated Cable Chest Press', category: 'petto', muscleImages: ['petto.png', 'push.png'], primaryMuscle: 'Grande pettorale', secondaryMuscles: 'Tricipiti, Deltoide anteriore', execution: 'Sdraiati sulla panca con i piedi a terra. Afferra il bilanciere con presa più larga delle spalle. Abbassa il bilanciere fino al petto mantenendo i gomiti a circa 45°. Spingi verso l\'alto in modo deciso.', tips: 'Retrai le scapole e mantienile bloccate. Non rimbalzare il peso sul petto.', gifFilename: 'seated-cable-chest-press'),
  ExerciseInfo(name: 'Seated Cable Close Grip Chest Press', nameEn: 'Seated Cable Close Grip Chest Press', category: 'petto', muscleImages: ['tricipiti.png', 'petto.png'], primaryMuscle: 'Tricipiti', secondaryMuscles: 'Grande pettorale, Deltoide anteriore', execution: 'Sdraiati sulla panca con presa alla larghezza delle spalle. Abbassa il bilanciere mantenendo i gomiti vicini al busto. Spingi verso l\'alto contraendo i tricipiti.', tips: 'Tieni i gomiti aderenti al corpo. Evita di allargare i gomiti.', gifFilename: 'seated-cable-close-grip-chest-press'),
  ExerciseInfo(name: 'Seated Cable Rope Row', nameEn: 'Seated Cable Rope Row', category: 'dorso', muscleImages: ['dorso.png', 'bicipiti.png'], primaryMuscle: 'Gran dorsale, Romboidi', secondaryMuscles: 'Bicipiti, Trapezio, Deltoide posteriore', execution: 'Siediti al cavo basso con i piedi sui supporti. Tira la maniglia verso il punto vita mantenendo la schiena dritta. Contrai i muscoli della schiena e torna lentamente.', tips: 'Non arrotondare la schiena. Controlla la fase di allungamento.', gifFilename: 'seated-cable-rope-row'),
  ExerciseInfo(name: 'Seated Cable Row', nameEn: 'Seated Cable Row', category: 'dorso', muscleImages: ['dorso.png', 'bicipiti.png'], primaryMuscle: 'Gran dorsale, Romboidi', secondaryMuscles: 'Bicipiti, Trapezio, Deltoide posteriore', execution: 'Siediti al cavo basso con i piedi sui supporti. Tira la maniglia verso il punto vita mantenendo la schiena dritta. Contrai i muscoli della schiena e torna lentamente.', tips: 'Non arrotondare la schiena. Controlla la fase di allungamento.', gifFilename: 'seated-cable-row'),
