  ExerciseInfo(name: 'Seated Dumbbell Front Raise', nameEn: 'Seated Dumbbell Front Raise', category: 'spalle', muscleImages: ['spalle.png'], primaryMuscle: 'Deltoide anteriore', secondaryMuscles: 'Grande pettorale (fascio clavicolare), Trapezio', execution: 'In piedi con l\'attrezzo davanti alle cosce. Alza le braccia davanti a te fino all\'altezza delle spalle mantenendo i gomiti leggermente piegati. Abbassa lentamente.', tips: 'Mantieni il busto stabile evitando di dondolare. Controlla la discesa.', gifFilename: 'seated-dumbbell-front-raise'),
  ExerciseInfo(name: 'Seated Dumbbell Lateral Raise', nameEn: 'Seated Dumbbell Lateral Raise', category: 'spalle', muscleImages: ['spalle.png'], primaryMuscle: 'Deltoide laterale', secondaryMuscles: 'Trapezio superiore, Sovraspinato', execution: 'In piedi con un manubrio per mano lungo i fianchi. Alza le braccia lateralmente fino all\'altezza delle spalle mantenendo i gomiti leggermente piegati. Abbassa lentamente.', tips: 'Non portare le braccia oltre l\'altezza delle spalle. Ruota leggermente i polsi verso il basso (come versando acqua) per isolare il deltoide laterale.', gifFilename: 'seated-dumbbell-lateral-raise'),
